const { execFile } = require('child_process');
const path = require('path');

const resizeImage = (inputFile, outputFile, dimensions, effects) => {
    const imageMagickPath = 'magick'; // or 'gm' for GraphicsMagick
    const args = ['convert', inputFile, '-resize', dimensions];

    const effectMap = {
        grayscale: '-colorspace',
        sepia: '-sepia-tone',
        blur: '-blur',
        enhance: '-enhance'
    };

    effects.forEach(effect => {
        if (effectMap[effect]) {
            args.push(effectMap[effect]);
            if (effect === 'sepia') {
                args.push('80%'); // Example value for sepia tone
            } else if (effect === 'blur') {
                args.push('0x8'); // Example value for blur
            }
        }
    });

    args.push(outputFile);

    execFile(imageMagickPath, args, (error, stdout, stderr) => {
        if (error) {
            console.error(`Error: ${error.message}`);
            return;
        }
        if (stderr) {
            console.error(`stderr: ${stderr}`);
            return;
        }
        console.log(`Image resized and saved to ${outputFile}`);
    });
};

// Example usage
resizeImage('user_photo.jpg', 'thumb.jpg', '200x200', ['grayscale', 'enhance']);